export type DeepSignal<T> = Signal<T> &
  (IsKnownRecord<T> extends true
    ? Readonly<{
        [K in keyof T]: IsKnownRecord<T[K]> extends true
          ? DeepSignal<T[K]>
          : Signal<T[K]>;
      }>
    : unknown);

calcStylesByGroup(group: 'center' | 'right' | 'left'): NgStyle['ngStyle'] {
  const widths = this._columnGroupWidths();

  return {
    width: `${widths[group]}px`
  };
}

ng1AppModule.component('ng1Hero', {
  bindings: {hero: '<', onRemove: '&'},
  transclude: true,
  template: `<div class="title" ng-transclude></div>
             <h2>{{ $ctrl.hero.name }}</h2>
             <p>{{ $ctrl.hero.description }}</p>
             <button ng-click="$ctrl.onRemove()">Remove</button>`,
});

if (!this.hasStarted()) {
  this._onStartFns.forEach((fn) => fn());
  this._onStartFns = [];
  this._started = true;
  if (this._specialStyles) {
    this._specialStyles.start();
  }
}

const interval = setInterval(
  () => {
    currentP += 1;
    if (currentP <= 100) this.progress.set(currentP);
    if (currentP >= 100) clearInterval(interval);
  },
  Math.max(this.latency() / 80, 5),
);

if ((tNode.type & expectedTypes) === 0) {
  throwError(
    message ||
      `Expected [${toTNodeTypeAsString(expectedTypes)}] but got ${toTNodeTypeAsString(
        tNode.type,
      )}.`,
  );
}

return !!(
  d1 &&
  d2 &&
  this._dateAdapter.getMonth(d1) == this._dateAdapter.getMonth(d2) &&
  this._dateAdapter.getYear(d1) == this._dateAdapter.getYear(d2)
);

if (this._pane) {
  coerceArray(cssClasses).forEach(cssClass => {
    if (cssClass !== '' && this._appliedPanelClasses.indexOf(cssClass) === -1) {
      this._appliedPanelClasses.push(cssClass);
      this._pane.classList.add(cssClass);
    }
  });
}

if (this._locale() === 'ja-JP') {
  return 'YYYY/MM/DD';
} else if (this._locale() === 'fr') {
  return 'DD/MM/YYYY';
}

return (
  (ts.isFunctionLike(node) && !getImmediatelyInvokedFunctionExpression(node)) ||
  node.kind === ts.SyntaxKind.ModuleBlock ||
  node.kind === ts.SyntaxKind.SourceFile ||
  node.kind === ts.SyntaxKind.PropertyDeclaration
);

return (
  ((ts.isAccessor(node) && ts.isClassDeclaration(node.parent)) ||
    ts.isPropertyDeclaration(node)) &&
  getMemberName(node) !== null
);

return (
  (node instanceof TmplAstBoundAttribute && node.type === BindingType.TwoWay) ||
  (node instanceof TmplAstBoundEvent && node.type === ParsedEventType.TwoWay)
);

if (
  ngDecorators.length === 0 ||
  ngDecorators[0].args === null ||
  ngDecorators[0].args.length === 0 ||
  !ts.isObjectLiteralExpression(ngDecorators[0].args[0])
) {
  return null;
}

return Array.from(
  element.querySelectorAll<HTMLHeadingElement>(
    `h2[id]:not(docs-example-viewer h2):not([${TOC_SKIP_CONTENT_MARKER}]),` +
      `h3[id]:not(docs-example-viewer h3):not([${TOC_SKIP_CONTENT_MARKER}])`,
  ),
);

render(this.tree().nativeElement, this.treeMapRecords(), {
  padding: [20, 5, 5, 5],
  caption: (node) => `${node.id}: ${node.size.toFixed(3)} ms`,
  showNode: () => true,
});

if (leadingTodoText !== null) {
  replacements.push(
    insertPrecedingLine(node, info, '// TODO: Notes from signal input migration:'),
    ...cutStringToLineLimit(leadingTodoText, 70).map((line) =>
      insertPrecedingLine(node, info, `//  ${line}`),
    ),
  );
}

return !!(
  type.flags & ts.TypeFlags.BooleanLike ||
  type.flags & ts.TypeFlags.StringLike ||
  type.flags & ts.TypeFlags.NumberLike ||
  type.flags & ts.TypeFlags.Undefined ||
  type.flags & ts.TypeFlags.Null
);

const inputs = potentiallyNarrowedInputs.map((i) => ({
  ref: i,
  key: i.targetField.key,
  pastCount: this.seenKnownFieldsCount.get(i.targetField.key) ?? 0,
}));

if (
  !ts.isTypeReferenceNode(node) ||
  !ts.isIdentifier(node.typeName) ||
  node.typeName.text !== 'Partial'
) {
  return null;
}

const inheritedTypes = (this.classToParents.get(clazz) ?? []).map((c) =>
      this.checker.getTypeAtLocation(c),
    );

if (startToken.parts[0] === 'default never' && this._attemptCharCode(chars.$SEMICOLON)) {
  this._beginToken(TokenType.BLOCK_OPEN_END);
  this._endToken([]);
  this._beginToken(TokenType.BLOCK_CLOSE);
  this._endToken([]);
  return;
}

if (bindings.some((b) => b?.i18nMessage) !== null) {
  unit.create.push(
    ir.createI18nAttributesOp(unit.job.allocateXrefId(), new ir.SlotHandle(), op.xref),
  );
}

if (
  this._activeItem !== null &&
  this._trackByFn(activeItem) === this._trackByFn(this._activeItem)
) {
  return;
}

if (x !== this._passiveTransform.x || y !== this._passiveTransform.y) {
  this.setFreeDragPosition({y, x});
}

const shouldBeFlushHorizontally =
      (width === '100%' || width === '100vw') &&
      (!maxWidth || maxWidth === '100%' || maxWidth === '100vw');

const shouldBeFlushVertically =
      (height === '100%' || height === '100vh') &&
      (!maxHeight || maxHeight === '100%' || maxHeight === '100vh');

const invalidateEdge = (from: GraphNode<T>, to: GraphNode<T>) => {
  if (!invalidatedEdges.has(from)) {
    invalidatedEdges.set(from, new Set());
  }
  invalidatedEdges.get(from)!.add(to);
};

const filterEdges = (from: GraphNode<T>, edges: Set<GraphNode<T>>) => {
  return Array.from(edges).filter(
    (e) => !invalidatedEdges.has(from) || !invalidatedEdges.get(from)!.has(e),
  );
};

if (cd === 'acx-on-push' || (0 < majorVer && majorVer < 22 && cd === 'ng-on-push')) {
  return 'OnPush';
}

const isImplicit =
      this._implicitTags.some((tag) => nodeName === tag) &&
      !this._inIcu &&
      !this._isInTranslatableSection;

if (
  (this._tempOnlyFile !== null && path !== this._tempOnlyFile) ||
  this._excludedFiles?.test(path)
) {
  return '';
}

if (topMargin === 0 && bottomMargin === 0 && startMargin === 0 && endMargin === 0) {
  this._clearCss();
  return;
}

return [
  insertPrecedingLine(node, programInfo, `// TODO: Skipped for migration because:`),
  ...lines.map((line) => insertPrecedingLine(node, programInfo, `//  ${line}`)),
];

const inheritedMember = inheritedTypes
      .map((t) => t.getProperty(memberName))
      .find((m) => m !== undefined);
